import android.content.Context;
import android.content.SharedPreferences;
import android.hardware.fingerprint.FingerprintManager;
import android.os.Build;
import android.os.CancellationSignal;
import android.support.annotation.RequiresApi;
import android.support.v4.hardware.fingerprint.FingerprintManagerCompat;
import android.widget.Toast;

@RequiresApi(api = Build.VERSION_CODES.M)
public class BiometricAuth {
    private static final String PREFERENCES_NAME = "biometric_auth";
    private static final String KEY_AUTHENTICATED = "authenticated";

    private Context context;
    private FingerprintManagerCompat fingerprintManager;
    private SharedPreferences preferences;

    public BiometricAuth(Context context) {
        this.context = context;
        this.fingerprintManager = FingerprintManagerCompat.from(context);
        this.preferences = context.getSharedPreferences(PREFERENCES_NAME, Context.MODE_PRIVATE);
    }

    public void authenticate() {
        if (!isBiometricAuthEnabled()) {
            return;
        }

        CancellationSignal cancellationSignal = new CancellationSignal();
        FingerprintManagerCompat.AuthenticationCallback authenticationCallback = new FingerprintManagerCompat.AuthenticationCallback() {
            @Override
            public void onAuthenticationError(int errorCode, CharSequence errString) {
                super.onAuthenticationError(errorCode, errString);
                Toast.makeText(context, "Biometric authentication failed", Toast.LENGTH_SHORT).show();
            }

            @Override
            public void onAuthenticationSucceeded(FingerprintManagerCompat.AuthenticationResult result) {
                super.onAuthenticationSucceeded(result);
                preferences.edit().putBoolean(KEY_AUTHENTICATED, true).apply();
                Toast.makeText(context, "Biometric authentication succeeded", Toast.LENGTH_SHORT).show();
            }
        };

        fingerprintManager.authenticate(null, 0, cancellationSignal, authenticationCallback, null);
    }

    public boolean isBiometricAuthEnabled() {
        return preferences.getBoolean(KEY_AUTHENTICATED, false);
    }
}